import { GoogleGenAI } from "@google/genai";
import { GenerationMode, VideoGenerationConfig, VideoStyle, ImageStyle, ImageQuality } from '../types';

const getStyleInstruction = (style: ImageStyle, customStyle: string): string => {
  if (style === ImageStyle.DEFAULT) {
    return '';
  }
  if (style === ImageStyle.CUSTOM) {
    return customStyle ? ` The image must be in the following style: ${customStyle}.` : '';
  }
  if (style === ImageStyle.GOOGLE) {
    return ' The image must be in the Google style: vibrant, primary colors, clean lines, modern, minimalist, with a playful and friendly touch. Flat design with subtle shadows.';
  }
  return ` The image must be in a ${style.toLowerCase()} style.`;
};

const constructPrompt = (prompt: string, mode: GenerationMode): string => {
  switch (mode) {
    case GenerationMode.THUMBNAIL:
      return `Create a high-impact, VIRAL YouTube thumbnail base for: '${prompt}'. 
      COMPOSITION & CTR META:
      - SUBJECT: Exaggerated "shocked" expression. Wide eyes, open mouth, high emotion. Place subject on the far right or far left to leave clear space for text.
      - BACKGROUND: High-contrast gradient (e.g., Deep Red to Black). Use cinematic motion blur on background elements like YouTube logos, dollar signs, or abstract sparks.
      - LIGHTING: Aggressive studio rim lighting (Backlighting) in neon colors to separate subject from background.
      - STYLE: Super-sharp focus, HDR polished, 4K professional photography style. 
      - TEXT PREPARATION: Leave a significant "empty" zone for large text overlays.
      - ELEMENTS: Include subtle visual cues of "growth" or "urgency" if relevant.`;
    case GenerationMode.CARTOON:
      return `A masterpiece character illustration of '${prompt}' in a modern 3D Disney/Pixar style. Soft shadows, vibrant skin tones, and expressive storytelling features. Square aspect ratio.`;
    case GenerationMode.STORY_IMAGE:
      return `Cinematic concept art for: '${prompt}'. Focused on epic scale and emotional atmosphere. 9:16 format, no text.`;
    case GenerationMode.SOCIAL:
      return `Premium minimal social media post design for: '${prompt}'. Swiss-style typography and high-end texture. Square aspect ratio.`;
    case GenerationMode.VERTICAL_STORY:
      return `Dynamic vertical story layout for: '${prompt}'. 9:16 vertical ratio with modern design aesthetics.`;
    default:
      return prompt;
  }
};

export const generateImage = async (
  prompt: string, 
  mode: GenerationMode, 
  imageStyle: ImageStyle, 
  customImageStyle: string,
  quality: ImageQuality = ImageQuality.STANDARD
): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  let fullPrompt = constructPrompt(prompt, mode);
  const styleInstruction = getStyleInstruction(imageStyle, customImageStyle);
  fullPrompt += styleInstruction;

  let aspectRatio: '16:9' | '1:1' | '9:16' = '16:9';
  if (mode === GenerationMode.CARTOON || mode === GenerationMode.SOCIAL) {
    aspectRatio = '1:1';
  } else if (mode === GenerationMode.VERTICAL_STORY || mode === GenerationMode.STORY_IMAGE) {
    aspectRatio = '9:16';
  }

  // Use gemini-2.5-flash-image for standard and gemini-3-pro-image-preview for high quality.
  // Both use the generateContent method which is more robust for general API keys.
  const model = quality === ImageQuality.STANDARD ? 'gemini-2.5-flash-image' : 'gemini-3-pro-image-preview';
  const imageSize = quality === ImageQuality.HIGH ? "2K" : quality === ImageQuality.ULTRA ? "4K" : "1K";

  const response = await ai.models.generateContent({
    model: model,
    contents: { parts: [{ text: fullPrompt }] },
    config: {
      imageConfig: {
        aspectRatio: aspectRatio,
        ...(model === 'gemini-3-pro-image-preview' ? { imageSize } : {})
      },
    },
  });

  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }

  throw new Error("No image was generated by the API.");
};

export const generateVideo = async (
  prompt: string, 
  config: VideoGenerationConfig, 
  onProgress?: (status: string) => void
): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const stylePrompt = config.style === VideoStyle.DEFAULT ? 'animated' : config.style;
  const fullPrompt = `A high-quality, ${stylePrompt} style video of '${prompt}'. The video should be approximately ${config.duration} seconds long.`;

  if (onProgress) onProgress("Sending request to Gemini...");

  let operation = await ai.models.generateVideos({
    model: 'veo-3.1-fast-generate-preview',
    prompt: fullPrompt,
    config: {
      numberOfVideos: 1,
      aspectRatio: config.aspectRatio,
      resolution: '720p',
    }
  });

  if (onProgress) onProgress("Video generation started...");

  const POLL_INTERVAL = 5000;
  let elapsedSeconds = 0;

  while (!operation.done) {
    await new Promise(resolve => setTimeout(resolve, POLL_INTERVAL));
    elapsedSeconds += POLL_INTERVAL / 1000;

    if (onProgress) {
        onProgress(`Rendering video... (~${elapsedSeconds}s elapsed)`);
    }

    operation = await ai.operations.getVideosOperation({ operation: operation });
  }

  if (onProgress) onProgress("Finalizing video...");

  const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;

  if (downloadLink) {
    return `${downloadLink}&key=${process.env.API_KEY}`;
  } else {
    throw new Error("No video was generated by the API or the operation failed.");
  }
};

import React, { useState, useCallback, useEffect } from 'react';
import { Header } from './components/Header';
import { GeneratorControls } from './components/GeneratorControls';
import { ImageDisplay } from './components/ImageDisplay';
import { Footer } from './components/Footer';
import { HistoryPanel } from './components/HistoryPanel';
import { DownloadModal } from './components/DownloadModal';
import { GenerationMode, VideoGenerationConfig, VideoStyle, ImageStyle, HistoryItem, ImageQuality } from './types';
import { generateImage, generateVideo } from './services/geminiService';

declare global {
  // Augment the existing AIStudio interface. 
  // By defining the interface and not re-declaring the property on Window, 
  // we avoid conflicts with the existing definition in the environment.
  interface AIStudio {
    hasSelectedApiKey: () => Promise<boolean>;
    openSelectKey: () => Promise<void>;
  }
}

const App: React.FC = () => {
  const [mode, setMode] = useState<GenerationMode>(GenerationMode.THUMBNAIL);
  const [prompt, setPrompt] = useState<string>('');
  const [generatedMediaUrl, setGeneratedMediaUrl] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [loadingMessage, setLoadingMessage] = useState<string>('');
  const [error, setError] = useState<string | null>(null);
  const [videoConfig, setVideoConfig] = useState<VideoGenerationConfig>({
    duration: 4,
    style: VideoStyle.DEFAULT,
    aspectRatio: '16:9',
  });
  const [imageStyle, setImageStyle] = useState<ImageStyle>(ImageStyle.DEFAULT);
  const [customImageStyle, setCustomImageStyle] = useState<string>('');
  const [imageQuality, setImageQuality] = useState<ImageQuality>(ImageQuality.STANDARD);
  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [isDownloadModalOpen, setIsDownloadModalOpen] = useState(false);

  useEffect(() => {
    try {
      const storedHistory = localStorage.getItem('generationHistory');
      if (storedHistory) {
        setHistory(JSON.parse(storedHistory));
      }
    } catch (error) {
      console.error("Failed to load history from localStorage", error);
    }
  }, []);

  const addToHistory = useCallback((newItem: HistoryItem) => {
    setHistory(prevHistory => {
      const updatedHistory = [newItem, ...prevHistory].slice(0, 50); // Keep max 50 items
      try {
        localStorage.setItem('generationHistory', JSON.stringify(updatedHistory));
      } catch (error) {
        console.error("Failed to save history to localStorage", error);
      }
      return updatedHistory;
    });
  }, []);

  const ensureApiKey = async () => {
    const hasKey = await window.aistudio.hasSelectedApiKey();
    if (!hasKey) {
      await window.aistudio.openSelectKey();
      // Proceed after triggering openSelectKey as per race condition mitigation
      return true;
    }
    return true;
  };

  const handleApiError = async (e: any, customPrefix: string) => {
    console.error(e);
    let errorMessage = e instanceof Error ? e.message : 'An unknown error occurred.';

    // Check for 403 or specific permission errors
    const isPermissionError = 
      errorMessage.includes("403") || 
      errorMessage.toLowerCase().includes("permission denied") || 
      errorMessage.toLowerCase().includes("caller does not have permission") ||
      errorMessage.includes("Requested entity was not found");

    if (isPermissionError) {
        await window.aistudio.openSelectKey();
        setError("API permission error. Please ensure you've selected a valid API key from a paid project with necessary APIs enabled.");
    } else {
        setError(`${customPrefix}. Please check your prompt or try again later.`);
    }
  };

  const runImageGeneration = useCallback(async (
    genPrompt: string,
    genMode: GenerationMode,
    genImageStyle: ImageStyle,
    genCustomImageStyle: string,
    genQuality: ImageQuality
  ) => {
    if (!genPrompt.trim()) {
      setError('Please enter a prompt.');
      return;
    }

    // Proactively check for key if high quality or video is requested
    if (genQuality !== ImageQuality.STANDARD) {
      await ensureApiKey();
    }

    setIsLoading(true);
    setGeneratedMediaUrl(null);
    setError(null);
    setLoadingMessage(genMode === GenerationMode.STORY_IMAGE ? 'Visualizing your story...' : 'Generating your image...');

    try {
      const mediaUrl = await generateImage(genPrompt, genMode, genImageStyle, genCustomImageStyle, genQuality);
      setGeneratedMediaUrl(mediaUrl);
      const newItem: HistoryItem = {
        id: new Date().toISOString(),
        timestamp: new Date().toISOString(),
        prompt: genPrompt,
        mode: genMode,
        imageStyle: genImageStyle,
        customImageStyle: genCustomImageStyle,
        imageDataUrl: mediaUrl,
        quality: genQuality,
      };
      addToHistory(newItem);
    } catch (e) {
      await handleApiError(e, `Failed to generate ${genMode.toLowerCase()}`);
    } finally {
      setIsLoading(false);
      setLoadingMessage('');
    }
  }, [addToHistory]);

  const handleGenerate = useCallback(async () => {
    if (mode === GenerationMode.VIDEO) {
        if (!prompt.trim()) {
          setError('Please enter a prompt to generate content.');
          return;
        }
        await ensureApiKey();
        setIsLoading(true);
        setGeneratedMediaUrl(null);
        setError(null);
        setLoadingMessage('Initializing video generation...');
        try {
            const mediaUrl = await generateVideo(prompt, videoConfig, (status) => {
                setLoadingMessage(status);
            });
            setGeneratedMediaUrl(mediaUrl);
        } catch (e) {
            await handleApiError(e, "Failed to generate video");
        } finally {
            setIsLoading(false);
            setLoadingMessage('');
        }
    } else {
        await runImageGeneration(prompt, mode, imageStyle, customImageStyle, imageQuality);
    }
  }, [prompt, mode, imageStyle, customImageStyle, imageQuality, videoConfig, runImageGeneration]);

  const handleSelectHistoryItem = (item: HistoryItem) => {
    setGeneratedMediaUrl(item.imageDataUrl);
    setPrompt(item.prompt);
    setMode(item.mode);
    setImageStyle(item.imageStyle);
    setCustomImageStyle(item.customImageStyle);
    if (item.quality) setImageQuality(item.quality);
  };

  const handleRegenerateFromHistory = (item: HistoryItem) => {
    setPrompt(item.prompt);
    setMode(item.mode);
    setImageStyle(item.imageStyle);
    setCustomImageStyle(item.customImageStyle);
    const quality = item.quality || ImageQuality.STANDARD;
    setImageQuality(quality);
    runImageGeneration(item.prompt, item.mode, item.imageStyle, item.customImageStyle, quality);
  };

  const handleDeleteHistoryItem = (id: string) => {
    const updatedHistory = history.filter(item => item.id !== id);
    setHistory(updatedHistory);
    localStorage.setItem('generationHistory', JSON.stringify(updatedHistory));
  };

  const handleClearHistory = () => {
    setHistory([]);
    localStorage.removeItem('generationHistory');
  };

  return (
    <div className="min-h-screen bg-gray-900 text-white font-sans flex flex-col relative overflow-x-hidden">
      <Header onOpenDownload={() => setIsDownloadModalOpen(true)} />

      {/* Floating Download Button (Bottom-Right Corner) */}
      <button 
        onClick={() => setIsDownloadModalOpen(true)}
        className="fixed bottom-6 right-6 z-50 p-4 bg-gradient-to-tr from-indigo-600 to-purple-600 text-white rounded-full shadow-2xl hover:scale-110 active:scale-95 transition-all duration-300 group flex items-center gap-2 overflow-hidden max-w-[56px] hover:max-w-[160px]"
        aria-label="Download App"
      >
        <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 flex-shrink-0" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 18h.01M8 21h8a2 2 0 002-2V5a2 2 0 00-2-2H8a2 2 0 00-2 2v14a2 2 0 002 2z" />
        </svg>
        <span className="whitespace-nowrap font-bold text-sm opacity-0 group-hover:opacity-100 transition-opacity">Get App</span>
      </button>

      <main className="flex-grow container mx-auto px-4 py-8 flex flex-col lg:flex-row gap-8">
        <div className="lg:w-1/4 lg:sticky top-8 self-start">
          <GeneratorControls
            mode={mode}
            setMode={setMode}
            prompt={prompt}
            setPrompt={setPrompt}
            handleGenerate={handleGenerate}
            isLoading={isLoading}
            videoConfig={videoConfig}
            setVideoConfig={setVideoConfig}
            imageStyle={imageStyle}
            setImageStyle={setImageStyle}
            customImageStyle={customImageStyle}
            setCustomImageStyle={setCustomImageStyle}
            imageQuality={imageQuality}
            setImageQuality={setImageQuality}
          />
        </div>
        <div className="lg:w-1/2">
          <ImageDisplay
            isLoading={isLoading}
            loadingMessage={loadingMessage}
            generatedMedia={generatedMediaUrl}
            setGeneratedMedia={setGeneratedMediaUrl}
            error={error}
            mode={mode}
            videoConfig={mode === GenerationMode.VIDEO ? videoConfig : undefined}
          />
        </div>
        <div className="lg:w-1/4">
           <HistoryPanel
            history={history}
            onSelect={handleSelectHistoryItem}
            onRegenerate={handleRegenerateFromHistory}
            onDelete={handleDeleteHistoryItem}
            onClear={handleClearHistory}
           />
        </div>
      </main>
      <Footer />

      <DownloadModal 
        isOpen={isDownloadModalOpen} 
        onClose={() => setIsDownloadModalOpen(false)} 
      />
    </div>
  );
};

export default App;

