           >
             <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 text-indigo-400 group-hover:scale-110 transition-transform" fill="none" viewBox="0 0 24 24" stroke="currentColor">
               <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
             </svg>
             <span>Download App</span>
           </button>
        </div>

        <h1 className="text-4xl md:text-5xl font-extrabold text-transparent bg-clip-text bg-gradient-to-r from-purple-400 via-pink-500 to-red-500 tracking-tight">
          AI Studio Pro
        </h1>
        <p className="text-gray-400 mt-3 max-w-2xl mx-auto text-sm md:text-base font-medium">
          The all-in-one studio for professional thumbnails, cartoon art, and cinematic video.
        </p>

        {/* Mobile API Status Indicator */}
        <div className="md:hidden mt-4">
           <button 
             onClick={onOpenApiKey}
             className="flex items-center gap-2 text-xs font-bold px-3 py-1 bg-gray-800 rounded-full border border-gray-700"
           >
             <div className={`w-1.5 h-1.5 rounded-full ${hasApiKey ? 'bg-green-500' : 'bg-yellow-500'}`}></div>
             API: {hasApiKey ? 'Selected' : 'Action Required'}
           </button>
        </div>
      </div>
    </header>
  );
